// PERSISTER RESTORE

const persisterRestoreMarker = Symbol('persisterRestore')

export interface PersisterRestoreResult<
  TData = unknown,
  TError = DefaultError,
> {
  data: TData | undefined
  state: QueryState<TData, TError>
}

interface WrappedPersisterRestoreResult<
  TData = unknown,
  TError = DefaultError,
> extends PersisterRestoreResult<TData, TError> {
  [persisterRestoreMarker]: true
}

/**
 * Creates a marker value that can be returned from a query `persister` to
 * signal that a fully persisted query snapshot was restored instead of freshly
 * fetched.
 *
 * When TanStack Query encounters this marker as the result of a fetch, it will
 * adopt the provided `state` as the active query state verbatim (ending in an
 * `idle` fetchStatus) instead of turning the result into a normal success
 * fetch. This preserves stale markers, refetch-error state, failure counters,
 * timestamps, invalidation markers and infinite-query pagination state.
 */
export function createPersisterRestoreResult<
  TData = unknown,
  TError = DefaultError,
>(result: PersisterRestoreResult<TData, TError>): TData {
  return {
    [persisterRestoreMarker]: true,
    data: result.data,
    state: result.state,
  } as unknown as TData
}

function isPersisterRestoreResult(
  value: unknown,
): value is WrappedPersisterRestoreResult {
  return (
    typeof value === 'object' &&
    value !== null &&
    (value as Record<PropertyKey, unknown>)[persisterRestoreMarker] === true
  )
}

